class GameHomeCardRequest extends FormRequest{protected function prepareForValidation(){if(!GameHomeCardDestinationType::requiresValue($this->input('destination_type')))$this->merge(['destination_value'=>null]);$this->merge(['is_active'=>$this->boolean('is_active'),'opens_new_tab'=>$this->boolean('opens_new_tab')]);}public function authorize(){return true;}public function rules(){$card=$this->route('gameHomeCard');$id=$card?$card->id:null;$routes=array_keys(app(GameHomeCardRouteCatalog::class)->all());return['name'=>'required|string|max:255','code'=>['required','string','max:64','regex:/^[a-z0-9]+(?:-[a-z0-9]+)*$/',Rule::unique('game_home_cards','code')->ignore($id)],'destination_type'=>['required',Rule::in(GameHomeCardDestinationType::all())],'destination_value'=>['nullable','string','max:191',Rule::requiredIf(GameHomeCardDestinationType::requiresValue($this->input('destination_type'))),Rule::when($this->input('destination_type')===GameHomeCardDestinationType::ROUTE,Rule::in($routes))],'sort_order'=>'required|integer|min:0|max:100000','is_active'=>'required|boolean','opens_new_tab'=>'required|boolean','banner'=>'nullable|file|max:5120|mimetypes:image/png,image/jpeg,image/webp'];}}
